import sys
from typing import List

class Solution:
  def read_input(self) -> List[int]:
    return list(map(int, sys.stdin.readline().split()))

  def solve(self, arr: List[int]) -> int:
    n = len(arr)
    arr.sort()
    median = arr[n // 2]
    return sum(abs(x - median) for x in arr)

  def write_output(self, result: int) -> None:
    sys.stdout.write(str(result) + '\n')

if __name__ == '__main__':
  solution = Solution()
  n = int(sys.stdin.readline())
  arr = solution.read_input()
  result = solution.solve(arr)
  solution.write_output(result)

