#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
  void read_input(vector<int>& arr) {
    for (int i = 0; i < arr.size(); ++i) {
      cin >> arr[i];
    }
  }

  int solve(vector<int>& arr) {
    int n = arr.size();
    sort(arr.begin(), arr.end());
    int median = arr[n / 2];
    int result = 0;
    for (int i = 0; i < n; ++i) {
      result += abs(arr[i] - median);
    }
    return result;
  }

  friend ostream& operator<<(ostream& os, const Solution& solution) {
    for (int i = 0; i < solution.arr.size(); ++i) {
      os << solution.arr[i] << ' ';
    }
    return os;
  }

  vector<int> arr;
};

int main() {
  Solution solution;
  int n;
  cin >> n;
  solution.arr.resize(n);
  solution.read_input(solution.arr);
  int result = solution.solve(solution.arr);
  cout << result << endl;
  return 0;
}
